import{_ as s,o as n,c as e,ak as l}from"./chunks/framework.DwHlt8HN.js";const b=JSON.parse('{"title":"系统设计面试方法论：Scale 估算与高层设计","description":"","frontmatter":{},"headers":[],"relativePath":"interview/system-design/method.md","filePath":"interview/system-design/method.md","lastUpdated":1774284085000}'),i={name:"interview/system-design/method.md"};function p(r,a,t,c,o,d){return n(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="系统设计面试方法论-scale-估算与高层设计" tabindex="-1">系统设计面试方法论：Scale 估算与高层设计 <a class="header-anchor" href="#系统设计面试方法论-scale-估算与高层设计" aria-label="Permalink to “系统设计面试方法论：Scale 估算与高层设计”">​</a></h1><p>面试官抛出这道题的时候，你心里可能在想：又要设计 Twitter 了？</p><p>别慌。系统设计面试考的从来不是你能不能设计出 Twitter，而是你<strong>思考问题的方式</strong>。</p><p>就像老中医看病，先要望闻问切，再开药方。系统设计的第一步，永远是<strong>理解问题的边界</strong>。</p><h2 id="为什么要-scale-估算" tabindex="-1">为什么要 Scale 估算？ <a class="header-anchor" href="#为什么要-scale-估算" aria-label="Permalink to “为什么要 Scale 估算？”">​</a></h2><p>想象一下，你要去一个陌生的城市，你不知道它有多大，不知道有多少人口，你怎么规划路线？</p><p>Scale 估算就是给系统「量体温」——知道系统的规模，你才能判断该用什么方案。</p><p><strong>例子</strong>：如果系统只有 100 个用户，你用 Redis 做缓存就是杀鸡用牛刀；但如果是 1 亿用户，不用缓存，系统分分钟被流量冲垮。</p><h2 id="四步法-从模糊到清晰" tabindex="-1">四步法：从模糊到清晰 <a class="header-anchor" href="#四步法-从模糊到清晰" aria-label="Permalink to “四步法：从模糊到清晰”">​</a></h2><h3 id="第一步-clarify-requirements——问对问题" tabindex="-1">第一步： Clarify Requirements——问对问题 <a class="header-anchor" href="#第一步-clarify-requirements——问对问题" aria-label="Permalink to “第一步： Clarify Requirements——问对问题”">​</a></h3><p>面试官说「设计一个短链接系统」，你要问清楚：</p><ul><li>每天生成多少短链接？</li><li>点击量是多少？</li><li>需要支持自定义短链接吗？</li><li>要支持分析统计吗？</li></ul><p>这些问题决定了你后续的技术选型。</p><h3 id="第二步-capacity-estimation——量化规模" tabindex="-1">第二步： Capacity Estimation——量化规模 <a class="header-anchor" href="#第二步-capacity-estimation——量化规模" aria-label="Permalink to “第二步： Capacity Estimation——量化规模”">​</a></h3><p>用 Back-of-the-Envelope 估算：</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>假设：</span></span>
<span class="line"><span>- 日活用户：1 亿</span></span>
<span class="line"><span>- 每天发微博量：5 亿条</span></span>
<span class="line"><span>- 每条微博 200 字节</span></span>
<span class="line"><span>- 需要存储 3 年</span></span>
<span class="line"><span></span></span>
<span class="line"><span>存储量 = 5亿 × 365 × 3 × 200 字节 ≈ 10 PB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>看到 10 PB 这个数字，你就知道不能用普通数据库了。</p><h3 id="第三步-high-level-design——画框架" tabindex="-1">第三步： High-Level Design——画框架 <a class="header-anchor" href="#第三步-high-level-design——画框架" aria-label="Permalink to “第三步： High-Level Design——画框架”">​</a></h3><p>关键组件：</p><ul><li><strong>Load Balancer</strong>：流量入口，分发请求</li><li><strong>API Gateway</strong>：统一入口，做鉴权、限流</li><li><strong>Storage</strong>：根据场景选 MySQL、Cassandra、HBase</li><li><strong>Cache</strong>：Redis/Memcached 做缓存层</li><li><strong>Message Queue</strong>：削峰解耦</li></ul><h3 id="第四步-deep-dive——深入设计" tabindex="-1">第四步： Deep Dive——深入设计 <a class="header-anchor" href="#第四步-deep-dive——深入设计" aria-label="Permalink to “第四步： Deep Dive——深入设计”">​</a></h3><p>针对具体问题深入：</p><ul><li>如何做数据分片？</li><li>一致性如何保证？</li><li>缓存策略怎么设计？</li><li>怎么应对热点问题？</li></ul><h2 id="scale-估算实战-twitter-时间线" tabindex="-1">Scale 估算实战：Twitter 时间线 <a class="header-anchor" href="#scale-估算实战-twitter-时间线" aria-label="Permalink to “Scale 估算实战：Twitter 时间线”">​</a></h2><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>用户规模：</span></span>
<span class="line"><span>- 月活：3 亿</span></span>
<span class="line"><span>- 日发推：5 亿</span></span>
<span class="line"><span>- 日点击量：500 亿</span></span>
<span class="line"><span></span></span>
<span class="line"><span>存储估算：</span></span>
<span class="line"><span>- 每条推文 200 字节</span></span>
<span class="line"><span>- 需要存储 3 年</span></span>
<span class="line"><span>- 总存储量 = 5亿 × 365 × 3 × 200 = 10.95 PB</span></span>
<span class="line"><span></span></span>
<span class="line"><span>QPS 估算：</span></span>
<span class="line"><span>- 假设 30% 用户看时间线</span></span>
<span class="line"><span>- 日活 = 1 亿</span></span>
<span class="line"><span>- 每用户每天刷 10 次</span></span>
<span class="line"><span>- 读 QPS = 1亿 × 30% × 10 / 86400 ≈ 3500 次/秒</span></span>
<span class="line"><span>- 峰值 QPS = 3500 × 3 = 10500 次/秒</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br></div></div><p>看到这个数字，你就知道需要：</p><ul><li>缓存层来抗读流量</li><li>读写分离来分散压力</li><li>可能需要推送模式来优化延迟</li></ul><h2 id="面试中的沟通技巧" tabindex="-1">面试中的沟通技巧 <a class="header-anchor" href="#面试中的沟通技巧" aria-label="Permalink to “面试中的沟通技巧”">​</a></h2><p>面试官不是想为难你，而是想看你的思考过程。</p><p><strong>好的沟通方式</strong>：</p><ul><li>「让我先确认一下系统的规模」</li><li>「如果用户量是 X，我预计 QPS 是 Y，存储量是 Z」</li><li>「基于这个规模，我建议采用 X 方案，因为...」</li></ul><p><strong>不好的沟通方式</strong>：</p><ul><li>一上来就开始画架构图</li><li>不问规模就开始写代码</li><li>方案确定后不再讨论 Trade-off</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to “总结”">​</a></h2><p>系统设计面试的核心不是「背答案」，而是「会思考」：</p><ol><li><strong>问清楚问题</strong>：规模决定方案</li><li><strong>量化估算</strong>：用数字说话</li><li><strong>先框架后细节</strong>：从粗到细</li><li><strong>讨论 Trade-off</strong>：没有完美的方案</li></ol><p>下次面试官问你设计 XX 系统，先深呼吸，然后说：</p><p>「在开始之前，我想先确认一下系统的规模...」</p>`,38)])])}const m=s(i,[["render",p]]);export{b as __pageData,m as default};
